using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public class ChargeTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task ChargeAsync_ValidTokenAndAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrEmpty(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_ValidToken_ReturnsUniqueChargeIds()
    {
        var result1 = await _gateway.ChargeAsync("tok_visa_1", 10.00m);
        var result2 = await _gateway.ChargeAsync("tok_visa_2", 20.00m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 25.00m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task ChargeAsync_EmptyToken_ThrowsArgumentException()
    {
        await _gateway.ChargeAsync(string.Empty, 10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public async Task ChargeAsync_NullToken_ThrowsArgumentNullException()
    {
        await _gateway.ChargeAsync(null!, 10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentOutOfRangeException()
    {
        await _gateway.ChargeAsync("tok_valid", 0m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentOutOfRangeException()
    {
        await _gateway.ChargeAsync("tok_valid", -5.00m);
    }

    [TestMethod]
    public async Task ChargeAsync_MinimumAmount_Succeeds()
    {
        var result = await _gateway.ChargeAsync("tok_valid", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_LargeAmount_Succeeds()
    {
        var result = await _gateway.ChargeAsync("tok_valid", 999_999.99m);

        Assert.IsTrue(result.Success);
    }
}

[TestClass]
public class RefundTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccess()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 50.00m);
        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsFalse(string.IsNullOrEmpty(refund.RefundId));
    }

    [TestMethod]
    public async Task RefundAsync_ValidCharge_ReturnsUniqueRefundId()
    {
        var charge1 = await _gateway.ChargeAsync("tok_visa_1", 10.00m);
        var charge2 = await _gateway.ChargeAsync("tok_visa_2", 20.00m);

        var refund1 = await _gateway.RefundAsync(charge1.ChargeId);
        var refund2 = await _gateway.RefundAsync(charge2.ChargeId);

        Assert.AreNotEqual(refund1.RefundId, refund2.RefundId);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await _gateway.RefundAsync(string.Empty);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
    {
        await _gateway.RefundAsync(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public async Task RefundAsync_NonexistentChargeId_ThrowsInvalidOperationException()
    {
        await _gateway.RefundAsync("ch_nonexistent_12345");
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public async Task RefundAsync_AlreadyRefundedCharge_ThrowsInvalidOperationException()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 30.00m);
        await _gateway.RefundAsync(charge.ChargeId);

        // Second refund on same charge should fail
        await _gateway.RefundAsync(charge.ChargeId);
    }
}

